// === LOGO BASE64 ===
const LOGO_B64 = "";

// === FOOTER LOGO INJECTION ===
document.getElementById('footer-logo').src = 'data:image/jpeg;base64,' + LOGO_B64;

(function() {
  const canvas = document.getElementById('logo3d');
  if (!canvas || !window.THREE) return;

  const renderer = new THREE.WebGLRenderer({ canvas, antialias: true, alpha: true });
  renderer.setSize(420, 420);
  renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
  renderer.shadowMap.enabled = true;

  const scene = new THREE.Scene();
  const camera = new THREE.PerspectiveCamera(45, 1, 0.1, 100);
  camera.position.set(0, 0, 7);

  const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
  scene.add(ambientLight);

  const dirLight = new THREE.DirectionalLight(0x00c2a8, 1.2);
  dirLight.position.set(5, 5, 5);
  scene.add(dirLight);

  const pointLight = new THREE.PointLight(0x00c2a8, 1.5, 20);
  scene.add(pointLight);

  const textureLoader = new THREE.TextureLoader();
  const logoTexture = textureLoader.load('data:image/jpeg;base64,' + LOGO_B64);

  const panelGeo = new THREE.BoxGeometry(3.2, 3.2, 0.15);
  const materials = [
    new THREE.MeshStandardMaterial({ color: 0x252a57, roughness: 0.3, metalness: 0.6 }),
    new THREE.MeshStandardMaterial({ color: 0x252a57, roughness: 0.3, metalness: 0.6 }),
    new THREE.MeshStandardMaterial({ color: 0x252a57, roughness: 0.3, metalness: 0.6 }),
    new THREE.MeshStandardMaterial({ color: 0x252a57, roughness: 0.3, metalness: 0.6 }),
    new THREE.MeshStandardMaterial({ map: logoTexture, roughness: 0.2, metalness: 0.3 }),
    new THREE.MeshStandardMaterial({ color: 0x1a1e48, roughness: 0.5 }),
  ];
  const panel = new THREE.Mesh(panelGeo, materials);
  scene.add(panel);

  const torusGeo = new THREE.TorusGeometry(2.2, 0.06, 16, 80);
  const torusMat = new THREE.MeshStandardMaterial({ color: 0x00c2a8, roughness: 0.2, metalness: 0.8, emissive: 0x003d36 });
  const torus = new THREE.Mesh(torusGeo, torusMat);
  torus.rotation.x = Math.PI / 6;
  scene.add(torus);

  const corners = [[-1.6, 1.6], [1.6, 1.6], [-1.6, -1.6], [1.6, -1.6]];
  corners.forEach(([x, y]) => {
    const geo = new THREE.BoxGeometry(0.18, 0.18, 0.3);
    const mat = new THREE.MeshStandardMaterial({ color: 0x00c2a8, metalness: 0.9, roughness: 0.1, emissive: 0x003d36 });
    const c = new THREE.Mesh(geo, mat);
    c.position.set(x, y, 0.12);
    scene.add(c);
  });

  let isDragging = false;
  let autoRotate = true;
  let autoResumeTimer;
  let prevX = 0;
  let prevY = 0;
  let velX = 0;
  let velY = 0;
  let rotX = 0;
  let rotY = 0;

  canvas.addEventListener('mousedown', e => { isDragging = true; prevX = e.clientX; prevY = e.clientY; clearTimeout(autoResumeTimer); autoRotate = false; });
  window.addEventListener('mouseup', () => { isDragging = false; autoResumeTimer = setTimeout(() => { autoRotate = true; }, 3000); });
  window.addEventListener('mousemove', e => {
    if (!isDragging) return;
    const dx = e.clientX - prevX;
    const dy = e.clientY - prevY;
    velX = dy * 0.008;
    velY = dx * 0.008;
    rotX += velX;
    rotY += velY;
    prevX = e.clientX;
    prevY = e.clientY;
  });
  canvas.addEventListener('touchstart', e => { isDragging = true; prevX = e.touches[0].clientX; prevY = e.touches[0].clientY; clearTimeout(autoResumeTimer); autoRotate = false; });
  window.addEventListener('touchend', () => { isDragging = false; autoResumeTimer = setTimeout(() => { autoRotate = true; }, 3000); });
  window.addEventListener('touchmove', e => {
    if (!isDragging) return;
    const dx = e.touches[0].clientX - prevX;
    const dy = e.touches[0].clientY - prevY;
    velX = dy * 0.008;
    velY = dx * 0.008;
    rotX += velX;
    rotY += velY;
    prevX = e.touches[0].clientX;
    prevY = e.touches[0].clientY;
  });

  let t = 0;
  function animate() {
    requestAnimationFrame(animate);
    t += 0.015;

    pointLight.position.x = Math.cos(t) * 4;
    pointLight.position.y = Math.sin(t * 0.7) * 3;
    pointLight.position.z = Math.sin(t) * 4;

    torus.rotation.y += 0.008;
    torus.rotation.z += 0.004;

    if (autoRotate) {
      velX *= 0.95;
      velY *= 0.95;
      rotY += 0.008;
    } else {
      velX *= 0.9;
      velY *= 0.9;
      rotX += velX;
      rotY += velY;
    }

    panel.rotation.x = rotX;
    panel.rotation.y = rotY;
    renderer.render(scene, camera);
  }

  animate();
})();

window.addEventListener('scroll', () => {
  document.getElementById('navbar').classList.toggle('scrolled', window.scrollY > 50);
});

const revealObserver = new IntersectionObserver(entries => {
  entries.forEach(entry => {
    if (entry.isIntersecting) {
      entry.target.classList.add('visible');
      revealObserver.unobserve(entry.target);
    }
  });
}, { threshold: 0.1 });

document.querySelectorAll('.reveal').forEach(el => revealObserver.observe(el));

if (window.emailjs) {
  emailjs.init('LFZqniCtP4wgYUGC-');
}

const contactForm = document.getElementById('contactForm');
const formConfirm = document.getElementById('formConfirm');

if (contactForm && formConfirm && window.emailjs) {
  contactForm.addEventListener('submit', async function(e) {
    e.preventDefault();

    try {
      await emailjs.sendForm('service_9nlij2c', 'template_praxintesis', this);
      this.reset();
      formConfirm.textContent = '✓ ¡Mensaje recibido! Te contactaremos en las próximas horas.';
      formConfirm.style.display = 'block';
    } catch (error) {
      console.error('EmailJS error:', error);
      formConfirm.textContent = 'No se pudo enviar el mensaje. Intenta de nuevo en unos minutos.';
      formConfirm.style.display = 'block';
    }
  });
}

function subscribeNewsletter() {
  const input = document.getElementById('newsletterEmail');
  if (!input.value || !/\S+@\S+\.\S+/.test(input.value)) {
    input.style.borderColor = '#ff6b6b';
    setTimeout(() => input.style.borderColor = '', 2000);
    return;
  }
  input.style.display = 'none';
  input.nextElementSibling.style.display = 'none';
  document.getElementById('newsletterConfirm').style.display = 'block';
}
